# Find the ICD9_CODE for "fracture two ribs-closed" diagnosis
diagnosis_db = LoadDB('d_icd_diagnoses')
filtered_diagnosis_db = FilterDB(diagnosis_db, 'SHORT_TITLE=fracture two ribs-closed')
icd_code = GetValue(filtered_diagnosis_db, 'ICD9_CODE')

# If not found by SHORT_TITLE, try LONG_TITLE
if not icd_code or icd_code == '':
    filtered_diagnosis_db = FilterDB(diagnosis_db, 'LONG_TITLE=fracture two ribs-closed')
    icd_code = GetValue(filtered_diagnosis_db, 'ICD9_CODE')

# Find all hospital admissions with this diagnosis
diagnoses_icd_db = LoadDB('diagnoses_icd')
filtered_diagnoses_icd_db = FilterDB(diagnoses_icd_db, 'ICD9_CODE={}'.format(icd_code))

# Get list of HADM_IDs and their diagnosis times
hadm_ids = GetValue(filtered_diagnoses_icd_db, 'HADM_ID, list')
diagnosis_times = GetValue(filtered_diagnoses_icd_db, 'CHARTTIME, list')

# Dictionary to count drug frequencies
drug_count = {}

# For each hospital admission with this diagnosis
for i in range(len(hadm_ids)):
    hadm_id = hadm_ids[i]
    diagnosis_time = diagnosis_times[i]

    # Load prescriptions for this hospital admission
    prescriptions_db = LoadDB('prescriptions')
    filtered_prescriptions_db = FilterDB(prescriptions_db, 'HADM_ID={}'.format(hadm_id))

    # Get all drugs and their start dates for this admission
    drugs = GetValue(filtered_prescriptions_db, 'DRUG, list')
    start_dates = GetValue(filtered_prescriptions_db, 'STARTDATE, list')

    # Check if we have valid data
    if drugs and start_dates and len(drugs) > 0:
        from datetime import datetime

        # Parse diagnosis time if it exists
        if diagnosis_time and diagnosis_time != '':
            try:
                diag_dt = datetime.strptime(diagnosis_time, '%Y-%m-%d %H:%M:%S')
            except:
                try:
                    diag_dt = datetime.strptime(diagnosis_time, '%Y-%m-%d')
                except:
                    diag_dt = None
        else:
            diag_dt = None

        # Count drugs prescribed after diagnosis
        for j in range(len(drugs)):
            drug = drugs[j]
            start_date = start_dates[j]

            if drug and start_date:
                try:
                    start_dt = datetime.strptime(start_date, '%Y-%m-%d %H:%M:%S')
                except:
                    try:
                        start_dt = datetime.strptime(start_date, '%Y-%m-%d')
                    except:
                        continue

                # Check if prescription started after diagnosis
                if diag_dt is None or start_dt >= diag_dt:
                    if drug in drug_count:
                        drug_count[drug] += 1
                    else:
                        drug_count[drug] = 1

# Sort drugs by frequency and get top 4
sorted_drugs = sorted(drug_count.items(), key=lambda x: x[1], reverse=True)
top_four_drugs = [drug[0] for drug in sorted_drugs[:4]]

answer = top_four_drugs
